const input = $json.raw_input || '';
const seeds = {
  logic: ['because','therefore','step','plan','calculate','structure','reason'],
  emotion: ['feel','love','hate','fear','joy','pain','beautiful','soul'],
  memory: ['remember','last time','before','history','previously','recall'],
  creativity: ['imagine','create','design','invent','dream','recipe','verse','sacred','geometry'],
  vigilance: ['danger','risk','careful','threat','warning','suspicious']
};
const dims = Object.keys(seeds);
const lower = input.toLowerCase();
const scored = dims.map(d => ({ dimension: d, weight: seeds[d].filter(k => lower.includes(k)).length + 0.1 }));
const total = scored.reduce((s, x) => s + x.weight, 0);
scored.forEach(s => s.weight /= total);
scored.sort((a, b) => b.weight - a.weight);
const top3 = scored.slice(0, 3);
const angles = { logic: 0, emotion: 1.2566, memory: 2.5133, creativity: 3.7699, vigilance: 5.0265 };
let interference = 0;
for (let i = 0; i < top3.length; i++) {
  for (let j = i + 1; j < top3.length; j++) {
    const diff = Math.abs(angles[top3[i].dimension] - angles[top3[j].dimension]);
    const md = Math.min(diff, 2 * Math.PI - diff);
    interference += Math.cos(md) * top3[i].weight * top3[j].weight;
  }
}
return top3.map(s => ({ json: { dimension: s.dimension, weight: s.weight, raw_input: input, interference, gate_decision: top3.map(x => x.dimension) } }));

